import java.util.*;

class MagicDictionary {
    Map<Integer, List<String>> word_list;

    public MagicDictionary() {
        word_list = new HashMap<>();
    }

    public void buildDict(String[] dictionary) {
        for (String word : dictionary) {
            int length = word.length();
            if (!word_list.containsKey(length)) {
                word_list.put(length, new ArrayList<String>());
            }
            word_list.get(length).add(word);
        }
    }

    public boolean search(String searchWord) {
        int length = searchWord.length();
        if (word_list.containsKey(length)) {
            for (String word : word_list.get(length)) {
                int diff = 0;
                for (int i = 0; i < length; i++) {
                    if (searchWord.charAt(i) != word.charAt(i)) diff++;
                }
                if (diff == 1) return true;
            }
        }
        return false;
    }
}
